from flask import Flask, request, jsonify
from pymongo import MongoClient
from bson import ObjectId
from werkzeug.security import generate_password_hash, check_password_hash
import os
from datetime import datetime
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# MongoDB connection
MONGO_URI = os.getenv('MONGO_URI', 'mongodb://localhost:27017/')
client = MongoClient(MONGO_URI)
db = client['content_management_system']

# Collections
users_collection = db['users']
documents_collection = db['documents']

# Helper functions
def validate_email(email):
    return '@' in email and '.' in email.split('@')[-1]

def validate_password(password):
    return len(password) >= 8

def serialize_document(doc):
    doc['_id'] = str(doc['_id'])
    return doc

def serialize_user(user):
    user['_id'] = str(user['_id'])
    user.pop('password', None)
    return user

# Routes
@app.route('/register', methods=['POST'])
def register():
    try:
        data = request.get_json()
        
        if not data or not all(k in data for k in ('username', 'email', 'password')):
            return jsonify({'error': 'Missing required fields'}), 400
            
        username = data['username'].strip()
        email = data['email'].strip().lower()
        password = data['password']
        
        if not validate_email(email):
            return jsonify({'error': 'Invalid email format'}), 400
            
        if not validate_password(password):
            return jsonify({'error': 'Password must be at least 8 characters'}), 400
            
        if users_collection.find_one({'$or': [{'username': username}, {'email': email}]}):
            return jsonify({'error': 'Username or email already exists'}), 409
            
        hashed_password = generate_password_hash(password)
        
        user = {
            'username': username,
            'email': email,
            'password': hashed_password,
            'created_at': datetime.utcnow(),
            'updated_at': datetime.utcnow()
        }
        
        result = users_collection.insert_one(user)
        user['_id'] = str(result.inserted_id)
        user.pop('password')
        
        logger.info(f"User registered: {username}")
        return jsonify({'message': 'User registered successfully', 'user': user}), 201
        
    except Exception as e:
        logger.error(f"Registration error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/login', methods=['POST'])
def login():
    try:
        data = request.get_json()
        
        if not data or not all(k in data for k in ('username', 'password')):
            return jsonify({'error': 'Missing required fields'}), 400
            
        username = data['username'].strip()
        password = data['password']
        
        user = users_collection.find_one({'username': username})
        
        if not user or not check_password_hash(user['password'], password):
            return jsonify({'error': 'Invalid credentials'}), 401
            
        user['_id'] = str(user['_id'])
        user.pop('password')
        
        logger.info(f"User logged in: {username}")
        return jsonify({'message': 'Login successful', 'user': user}), 200
        
    except Exception as e:
        logger.error(f"Login error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/users/<user_id>', methods=['GET'])
def get_user(user_id):
    try:
        user = users_collection.find_one({'_id': ObjectId(user_id)})
        
        if not user:
            return jsonify({'error': 'User not found'}), 404
            
        return jsonify({'user': serialize_user(user)}), 200
        
    except Exception as e:
        logger.error(f"Get user error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/documents', methods=['POST'])
def create_document():
    try:
        data = request.get_json()
        
        if not data or not all(k in data for k in ('title', 'content', 'author_id')):
            return jsonify({'error': 'Missing required fields'}), 400
            
        document = {
            'title': data['title'].strip(),
            'content': data['content'].strip(),
            'author_id': data['author_id'],
            'tags': data.get('tags', []),
            'created_at': datetime.utcnow(),
            'updated_at': datetime.utcnow()
        }
        
        result = documents_collection.insert_one(document)
        document['_id'] = str(result.inserted_id)
        
        logger.info(f"Document created: {document['title']}")
        return jsonify({'message': 'Document created successfully', 'document': serialize_document(document)}), 201
        
    except Exception as e:
        logger.error(f"Create document error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/documents', methods=['GET'])
def get_documents():
    try:
        page = int(request.args.get('page', 1))
        limit = int(request.args.get('limit', 10))
        skip = (page - 1) * limit
        
        query = {}
        if 'author_id' in request.args:
            query['author_id'] = request.args['author_id']
        if 'tag' in request.args:
            query['tags'] = request.args['tag']
            
        documents = list(documents_collection.find(query).skip(skip).limit(limit))
        total = documents_collection.count_documents(query)
        
        return jsonify({
            'documents': [serialize_document(doc) for doc in documents],
            'pagination': {
                'page': page,
                'limit': limit,
                'total': total,
                'pages': (total + limit - 1) // limit
            }
        }), 200
        
    except Exception as e:
        logger.error(f"Get documents error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/documents/<doc_id>', methods=['GET'])
def get_document(doc_id):
    try:
        document = documents_collection.find_one({'_id': ObjectId(doc_id)})
        
        if not document:
            return jsonify({'error': 'Document not found'}), 404
            
        return jsonify({'document': serialize_document(document)}), 200
        
    except Exception as e:
        logger.error(f"Get document error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/documents/<doc_id>', methods=['PUT'])
def update_document(doc_id):
    try:
        data = request.get_json()
        
        if not data:
            return jsonify({'error': 'No data provided'}), 400
            
        update_data = {
            'title': data.get('title', '').strip(),
            'content': data.get('content', '').strip(),
            'tags': data.get('tags', []),
            'updated_at': datetime.utcnow()
        }
        
        # Remove empty fields
        update_data = {k: v for k, v in update_data.items() if v != ''}
        
        if not update_data:
            return jsonify({'error': 'No valid fields to update'}), 400
            
        result = documents_collection.update_one(
            {'_id': ObjectId(doc_id)},
            {'$set': update_data}
        )
        
        if result.matched_count == 0:
            return jsonify({'error': 'Document not found'}), 404
            
        document = documents_collection.find_one({'_id': ObjectId(doc_id)})
        return jsonify({'message': 'Document updated successfully', 'document': serialize_document(document)}), 200
        
    except Exception as e:
        logger.error(f"Update document error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/documents/<doc_id>', methods=['DELETE'])
def delete_document(doc_id):
    try:
        result = documents_collection.delete_one({'_id': ObjectId(doc_id)})
        
        if result.deleted_count == 0:
            return jsonify({'error': 'Document not found'}), 404
            
        return jsonify({'message': 'Document deleted successfully'}), 200
        
    except Exception as e:
        logger.error(f"Delete document error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/search', methods=['GET'])
def search_documents():
    try:
        query = request.args.get('q', '').strip()
        
        if not query:
            return jsonify({'error': 'Search query is required'}), 400
            
        search_query = {
            '$or': [
                {'title': {'$regex': query, '$options': 'i'}},
                {'content': {'$regex': query, '$options': 'i'}},
                {'tags': {'$regex': query, '$options': 'i'}}
            ]
        }
        
        documents = list(documents_collection.find(search_query))
        
        return jsonify({
            'documents': [serialize_document(doc) for doc in documents],
            'count': len(documents)
        }), 200
        
    except Exception as e:
        logger.error(f"Search documents error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/aggregation', methods=['GET'])
def aggregate_documents():
    try:
        pipeline = [
            {
                '$group': {
                    '_id': '$author_id',
                    'document_count': {'$sum': 1},
                    'avg_length': {'$avg': {'$strLenCP': '$content'}}
                }
            },
            {
                '$lookup': {
                    'from': 'users',
                    'localField': '_id',
                    'foreignField': '_id',
                    'as': 'author_info'
                }
            },
            {
                '$unwind': '$author_info'
            },
            {
                '$project': {
                    'author_id': '$_id',
                    'author_name': '$author_info.username',
                    'document_count': 1,
                    'avg_length': 1,
                    '_id': 0
                }
            }
        ]
        
        results = list(documents_collection.aggregate(pipeline))
        
        return jsonify({'aggregation_results': results}), 200
        
    except Exception as e:
        logger.error(f"Aggregation error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/health', methods=['GET'])
def health_check():
    try:
        client.admin.command('ping')
        return jsonify({'status': 'healthy', 'database': 'connected'}), 200
    except Exception as e:
        logger.error(f"Health check error: {str(e)}")
        return jsonify({'status': 'unhealthy', 'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)